DROP TABLE IF EXISTS player_appearances;
DROP TABLE IF EXISTS matches;
CREATE TABLE matches (
  match_key TEXT PRIMARY KEY,
  season_id INTEGER,
  match_date TEXT,
  venue TEXT,
  team_one_ref TEXT,
  team_two_ref TEXT,
  toss_winner_ref TEXT,
  toss_decision TEXT,
  win_type TEXT,
  win_margin INTEGER,
  outcome_type TEXT,
  match_winner_ref TEXT,
  player_of_match_ref TEXT
);
CREATE TABLE player_appearances (
  match_key TEXT,
  player_ref TEXT,
  role_note TEXT,
  team_ref TEXT
);
